UPDATE public.questions SET
  stimulus_text = 'The process by which a bill becomes law is long and complex, involving many steps: first, a bill is introduced in either the House of Representatives or the Senate; second, the bill is referred to a committee; third, the bill is debated and amended on the floor of the House or Senate; fourth, the bill is voted on by the House or Senate; fifth, if the bill is approved by both the House and Senate, it is sent to the president; sixth, the president can either sign the bill into law or veto it; and seventh, if the president vetoes the bill, Congress can override the veto by a two-thirds vote in both the House and the Senate.',
  question_text = 'Which choice best combines the sentences at the underlined portion to create a grammatically correct and clear sentence?',
